var dynamicIds = pm.environment.get('dynamicUserIds') || '[]';
var ids = JSON.parse(dynamicIds);
pm.test('Delete users called', () => pm.expect(pm.response.code).to.be.within(200, 299));
pm.test('Response indicates count', () => pm.expect(pm.response.json().deletedCount || 0).to.exist);
pm.environment.set('cleanup_users_deleted', pm.response.json().deletedCount || 0);

var users = pm.response.json();
pm.test('41 seed users exist', () => {
  var activeCount = users.filter(u => u.is_active).length;
  pm.expect(activeCount).to.equal(41);
});
pm.test('No extra users remain', () => {
  pm.expect(users.length).to.be.lessThan(45);
});

var courses = pm.response.json();
pm.test('12+ seed courses exist', () => pm.expect(courses.length).to.be.at.least(12));
pm.test('No excess courses', () => pm.expect(courses.length).to.be.lessThan(50));
pm.environment.set('cleanup_courses_verified', 'true');

var teams = pm.response.json();
pm.test('50+ seed teams exist', () => pm.expect(teams.length).to.be.at.least(50));
pm.environment.set('cleanup_teams_verified', 'true');

var stats = pm.response.json();
var totalDynamic = (stats.dynamicUsers || 0) + (stats.dynamicCourses || 0) + (stats.dynamicAssignments || 0);
pm.test('All dynamic data deleted', () => pm.expect(totalDynamic).to.equal(0));
pm.environment.set('cleanup_atomicity_verified', 'true');

var users = pm.response.json();
var actualSeedCount = users.filter(u => u.is_active).length;
if (actualSeedCount !== 41) {
    pm.test('[ATOMICITY FAILURE] Seed data corrupted!', () => {
        pm.expect(actualSeedCount).to.equal(41);
    });
}

pm.test('Report available', () => pm.expect([200, 404]).to.include(pm.response.code));
var summary = {
    'users_deleted': pm.environment.get('cleanup_users_deleted') || 0,
    'courses_deleted': pm.environment.get('cleanup_courses_deleted') || 0,
    'assignments_deleted': pm.environment.get('cleanup_assignments_deleted') || 0,
    'teams_deleted': pm.environment.get('cleanup_teams_deleted') || 0,
    'submissions_deleted': pm.environment.get('cleanup_submissions_deleted') || 0,
    'files_deleted': pm.environment.get('cleanup_files_deleted') || 0,
    'atomicity_verified': pm.environment.get('cleanup_atomicity_verified') === 'true',
    'timestamp': new Date().toISOString()
};
pm.globals.set('cleanup_summary', JSON.stringify(summary));
console.log('CLEANUP SUMMARY: ' + JSON.stringify(summary));
